import{_ as t,c as o,o as s,ae as d}from"./chunks/framework.CDjunVez.js";const m=JSON.parse('{"title":"Website Terminal","description":"","frontmatter":{},"headers":[],"relativePath":"website/terminal.md","filePath":"website/terminal.md"}'),i={name:"website/terminal.md"};function a(r,e,n,c,l,h){return s(),o("div",null,[...e[0]||(e[0]=[d(`<h1 id="website-terminal" tabindex="-1">Website Terminal <a class="header-anchor" href="#website-terminal" aria-label="Permalink to &quot;Website Terminal&quot;">​</a></h1><p>Each website in KiwiPanel has a built-in web terminal accessible from the browser — no SSH client needed. The terminal runs as the website&#39;s Linux user with restricted permissions, so users can manage files, run dev tools, and debug without risking the rest of the server.</p><p>Navigate to <strong>Websites → (your site) → Terminal</strong> to open it, or click the terminal icon in the website dropdown menu.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The website terminal is designed for single-admin panel deployments. It provides strong isolation for a single trusted user but is not a substitute for full multi-tenant hosting security.</p></div><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li>Open the terminal page for your website</li><li>A WebSocket connection is established to the server agent</li><li>The agent spawns a restricted shell session running as your website&#39;s Linux user</li><li>On Linux systems, the shell runs inside a <strong>systemd sandbox</strong> with strict resource and filesystem isolation</li><li>You get an interactive terminal (powered by xterm.js) confined to your home directory</li></ol><p>The session automatically closes after 20 minutes of inactivity.</p><h2 id="what-you-can-do" tabindex="-1">What You Can Do <a class="header-anchor" href="#what-you-can-do" aria-label="Permalink to &quot;What You Can Do&quot;">​</a></h2><p>The terminal provides access to a curated set of ~70 commands covering common tasks:</p><table tabindex="0"><thead><tr><th>Category</th><th>Commands</th></tr></thead><tbody><tr><td>File operations</td><td><code>ls</code>, <code>cp</code>, <code>mv</code>, <code>rm</code>, <code>mkdir</code>, <code>touch</code>, <code>chmod</code>, <code>find</code>, <code>ln</code>, <code>du</code>, <code>df</code></td></tr><tr><td>Text processing</td><td><code>cat</code>, <code>head</code>, <code>tail</code>, <code>grep</code>, <code>sed</code>, <code>awk</code>, <code>cut</code>, <code>sort</code>, <code>diff</code>, <code>wc</code></td></tr><tr><td>Editors</td><td><code>nano</code>, <code>vi</code>, <code>vim</code></td></tr><tr><td>Archives</td><td><code>tar</code>, <code>gzip</code>, <code>zip</code>, <code>unzip</code>, <code>bzip2</code>, <code>xz</code></td></tr><tr><td>Network</td><td><code>curl</code>, <code>wget</code>, <code>ssh</code>, <code>scp</code>, <code>rsync</code></td></tr><tr><td>Dev tools</td><td><code>git</code>, <code>node</code>, <code>npm</code>, <code>npx</code>, <code>php</code>, <code>composer</code>, <code>python3</code>, <code>pip3</code>, <code>ruby</code>, <code>gem</code>, <code>wp</code></td></tr><tr><td>Utilities</td><td><code>echo</code>, <code>date</code>, <code>whoami</code>, <code>env</code>, <code>which</code>, <code>clear</code>, <code>ps</code>, <code>kill</code></td></tr></tbody></table><p>Commands not on this list are unavailable. Shell interpreters (<code>bash</code>, <code>sh</code>, <code>zsh</code>, etc.) and privileged commands (<code>sudo</code>, <code>su</code>, <code>mount</code>, <code>systemctl</code>, etc.) are intentionally excluded.</p><h2 id="directory-restriction" tabindex="-1">Directory Restriction <a class="header-anchor" href="#directory-restriction" aria-label="Permalink to &quot;Directory Restriction&quot;">​</a></h2><p>The terminal is locked to your website&#39;s home directory. You can navigate freely within it but cannot access system directories or other users&#39; files:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>user1@server:~$ cd public_html</span></span>
<span class="line"><span>user1@server:~/public_html$ cd ../logs</span></span>
<span class="line"><span>user1@server:~/logs$ cd /etc</span></span>
<span class="line"><span>kiwipanel: access denied — you cannot navigate outside your home directory</span></span>
<span class="line"><span>user1@server:~/logs$ cd ../../</span></span>
<span class="line"><span>kiwipanel: access denied — you cannot navigate outside your home directory</span></span></code></pre></div><p>This applies to <code>cd</code>, <code>pushd</code>, and <code>popd</code>. If the shell somehow ends up outside the home directory (e.g., via a sourced script), it is automatically snapped back on the next command.</p><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><p>The website terminal uses multiple layers of protection to prevent users from escaping their sandbox:</p><h3 id="systemd-sandbox-linux" tabindex="-1">Systemd Sandbox (Linux) <a class="header-anchor" href="#systemd-sandbox-linux" aria-label="Permalink to &quot;Systemd Sandbox (Linux)&quot;">​</a></h3><p>On Linux systems with systemd v249+, terminal sessions run inside a <strong>transient systemd service</strong> with the following security properties:</p><table tabindex="0"><thead><tr><th>Property</th><th>Description</th></tr></thead><tbody><tr><td><code>NoNewPrivileges=yes</code></td><td>Process cannot gain new privileges (e.g., via setuid binaries)</td></tr><tr><td><code>PrivateTmp=yes</code></td><td>Isolated <code>/tmp</code> directory per session — cannot see other users&#39; temp files</td></tr><tr><td><code>ProtectSystem=strict</code></td><td>Root filesystem is read-only — cannot modify system files</td></tr><tr><td><code>ProtectHome=tmpfs</code></td><td>Other users&#39; homes are invisible; only your own home is visible</td></tr><tr><td><code>BindPaths=&lt;home&gt;</code></td><td>Only your home directory is bind-mounted into the sandbox</td></tr><tr><td><code>TasksMax=50</code></td><td>Maximum 50 processes per session — fork bombs are capped</td></tr><tr><td><code>MemoryMax=256M</code></td><td>Maximum 256MB memory usage per session</td></tr><tr><td><code>MemoryHigh=200M</code></td><td>Memory throttling begins at 200MB</td></tr><tr><td><code>CPUQuota=50%</code></td><td>Maximum 50% CPU usage per session</td></tr><tr><td><code>ProtectKernelTunables=yes</code></td><td>Kernel tunables are read-only</td></tr><tr><td><code>ProtectKernelModules=yes</code></td><td>Cannot load/unload kernel modules</td></tr><tr><td><code>ProtectControlGroups=yes</code></td><td>cgroup hierarchy is read-only</td></tr><tr><td><code>LockPersonality=yes</code></td><td>Cannot change execution domain</td></tr><tr><td><code>RestrictSUIDSGID=yes</code></td><td>SUID/SGID execution is restricted</td></tr><tr><td><code>ProtectKernelLogs=yes</code></td><td>Kernel logs are read-only</td></tr><tr><td><code>ProtectClock=yes</code></td><td>Cannot change system clock</td></tr><tr><td><code>RestrictRealtime=yes</code></td><td>Cannot use real-time scheduling</td></tr><tr><td><code>SystemCallArchitectures=native</code></td><td>Only native syscalls allowed (no 32-bit compatibility)</td></tr><tr><td><code>RestrictAddressFamilies=AF_UNIX AF_INET AF_INET6</code></td><td>Only Unix, IPv4, and IPv6 sockets allowed</td></tr><tr><td><code>PrivatePIDs=yes</code> (v256+)</td><td>Other processes on the system are invisible</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The minimum supported systemd version is <strong>249</strong>. On systems with systemd v256+, <code>PrivatePIDs=yes</code> provides additional process isolation.</p></div><hr><h3 id="restricted-command-set" tabindex="-1">Restricted Command Set <a class="header-anchor" href="#restricted-command-set" aria-label="Permalink to &quot;Restricted Command Set&quot;">​</a></h3><p>The <code>PATH</code> is set exclusively to a shared <code>terminal-bin</code> directory (<code>/var/lib/kiwipanel/terminal-bin</code> on Linux, <code>/tmp/kiwipanel/terminal-bin</code> on macOS). This directory contains symlinks to approved commands only — it is owned by root and cannot be modified by the user.</p><h3 id="home-lock" tabindex="-1">Home Lock <a class="header-anchor" href="#home-lock" aria-label="Permalink to &quot;Home Lock&quot;">​</a></h3><p>A custom rcfile overrides <code>cd</code>, <code>pushd</code>, and <code>popd</code> builtins to reject any target outside the home directory. All override functions are marked <code>readonly</code> so the user cannot unset them.</p><h3 id="environment-variable-lock" tabindex="-1">Environment Variable Lock <a class="header-anchor" href="#environment-variable-lock" aria-label="Permalink to &quot;Environment Variable Lock&quot;">​</a></h3><p>Critical variables are locked down:</p><ul><li><code>PATH</code> — cannot be changed (enforced by readonly)</li><li><code>SHELL</code> — cannot be reassigned</li><li><code>ENV</code> and <code>BASH_ENV</code> — cannot be set (prevents loading alternative init scripts)</li><li><code>LESSSECURE</code> — set to <code>1</code> to disable less command escape sequences</li><li><code>GIT_TERMINAL_PROMPT</code> — set to <code>0</code> to prevent interactive git prompts</li></ul><h3 id="command-guard" tabindex="-1">Command Guard <a class="header-anchor" href="#command-guard" aria-label="Permalink to &quot;Command Guard&quot;">​</a></h3><p>A <strong>keystroke-level guard</strong> intercepts input before it reaches the PTY. It reconstructs the command line from individual bytes (handling backspace, Ctrl+C, Ctrl+U, etc.) and checks the assembled command when Enter is pressed.</p><p>If a dangerous command is detected, the guard:</p><ol><li>Absorbs the Enter keystroke (does not forward it to PTY)</li><li>Sends a warning message to the WebSocket (displayed to user)</li><li>Sends Ctrl+C to the PTY to clear the current line</li></ol><p>Blocked commands include:</p><table tabindex="0"><thead><tr><th>Category</th><th>Examples</th></tr></thead><tbody><tr><td>Filesystem destruction</td><td><code>rm -rf /</code>, <code>rm --no-preserve-root</code>, <code>find / -delete</code></td></tr><tr><td>Disk/device destruction</td><td><code>mkfs /dev/sda</code>, <code>dd of=/dev/sda</code></td></tr><tr><td>Fork/process bombs</td><td>\`:(){ :</td></tr><tr><td>Disk space exhaustion</td><td>Large <code>dd</code>/<code>fallocate</code>, <code>yes &gt; file</code></td></tr><tr><td>Memory exhaustion</td><td>Python memory bombs, <code>stress</code></td></tr><tr><td>Permission attacks</td><td><code>chmod 000 /</code>, <code>chown root /etc</code></td></tr><tr><td>Sensitive file access</td><td>Reading <code>/etc/shadow</code> (website terminals only)</td></tr><tr><td>Network abuse</td><td>Flood ping, netcat listeners (website terminals only)</td></tr><tr><td>Process killing</td><td><code>kill -9 1</code>, <code>pkill sshd</code></td></tr><tr><td>Shell escapes</td><td>Python <code>pty.spawn</code>, <code>os.system</code></td></tr></tbody></table><h3 id="privilege-drop" tabindex="-1">Privilege Drop <a class="header-anchor" href="#privilege-drop" aria-label="Permalink to &quot;Privilege Drop&quot;">​</a></h3><p>The shell process runs with the website user&#39;s UID/GID via kernel-level credential switching. Even if all shell-level restrictions were bypassed, the process would still only have the permissions of the unprivileged user.</p><h2 id="isolation-model-comparison" tabindex="-1">Isolation Model Comparison <a class="header-anchor" href="#isolation-model-comparison" aria-label="Permalink to &quot;Isolation Model Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Security Feature</th><th>Systemd Sandbox (v256+)</th><th>Systemd Sandbox (v249-255)</th><th>PHP Chroot Jail</th></tr></thead><tbody><tr><td>Root filesystem access</td><td><strong>Read-only</strong> (<code>ProtectSystem=strict</code>)</td><td><strong>Read-only</strong> (<code>ProtectSystem=strict</code>)</td><td><strong>Invisible</strong> (no <code>/</code> exists)</td></tr><tr><td>Read system files like <code>/etc/passwd</code></td><td><strong>Invisible</strong> (<code>ProtectHome=tmpfs</code>)</td><td><strong>Invisible</strong> (<code>ProtectHome=tmpfs</code>)</td><td><strong>Invisible</strong> (no <code>/etc</code> exists)</td></tr><tr><td>Other users&#39; homes</td><td><strong>Invisible</strong> (<code>ProtectHome=tmpfs</code>)</td><td><strong>Invisible</strong> (<code>ProtectHome=tmpfs</code>)</td><td><strong>Invisible</strong> (outside chroot)</td></tr><tr><td>See other users&#39; processes</td><td><strong>Invisible</strong> (<code>PrivatePIDs=yes</code>)</td><td>Visible (system v249-255 limitation)</td><td>Visible (no PID namespace)</td></tr><tr><td>Maximum processes</td><td><strong>50</strong> (<code>TasksMax=50</code>)</td><td><strong>50</strong> (<code>TasksMax=50</code>)</td><td>No limit</td></tr><tr><td>Maximum memory</td><td><strong>256MB</strong> (<code>MemoryMax=256M</code>)</td><td><strong>256MB</strong> (<code>MemoryMax=256M</code>)</td><td>No limit</td></tr><tr><td>CPU limit</td><td><strong>50%</strong> (<code>CPUQuota=50%</code>)</td><td><strong>50%</strong> (<code>CPUQuota=50%</code>)</td><td>No limit</td></tr><tr><td>Fork bomb / resource exhaustion</td><td><strong>Capped</strong> (by cgroup limits)</td><td><strong>Capped</strong> (by cgroup limits)</td><td>Not capped</td></tr><tr><td>Private <code>/tmp</code> per session</td><td><strong>Yes</strong> (<code>PrivateTmp=yes</code>)</td><td><strong>Yes</strong> (<code>PrivateTmp=yes</code>)</td><td>Yes (chroot <code>/tmp</code>)</td></tr><tr><td>Network access</td><td><strong>Yes</strong> (AF_INET/AF_INET6 allowed)</td><td><strong>Yes</strong> (AF_INET/AF_INET6 allowed)</td><td>Yes (if socket in chroot)</td></tr><tr><td>Minimum systemd version</td><td>256</td><td>249</td><td>N/A</td></tr></tbody></table><h2 id="hardening-for-multi-tenant-use" tabindex="-1">Hardening for Multi-Tenant Use <a class="header-anchor" href="#hardening-for-multi-tenant-use" aria-label="Permalink to &quot;Hardening for Multi-Tenant Use&quot;">​</a></h2><p>While KiwiPanel is designed for single-admin deployments, you can harden the environment for multi-tenant scenarios:</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The following suggestions assume you understand the security trade-offs. The systemd sandbox already provides strong isolation for most single-admin use cases.</p></div><ol><li><p><strong>Enable PHP Chroot Jail</strong> — For PHP websites, enable chroot isolation via the PHP Security settings. This provides stronger filesystem isolation than the systemd sandbox alone (system files are completely invisible, not just read-only).</p></li><li><p><strong>Configure Resource Limits</strong> — Adjust systemd sandbox limits in <code>/etc/systemd/system/kiwipanel-agent.service</code> if needed:</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Override with systemctl edit kiwipanel-agent</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Service]</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># These are defaults; increase if users need more</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># TasksMax is enforced via systemd-run arguments</span></span></code></pre></div></li><li><p><strong>PAM Limits</strong> — Ensure <code>/etc/security/limits.conf</code> has appropriate ulimits for website users:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>* soft nproc 50</span></span>
<span class="line"><span>* hard nproc 100</span></span>
<span class="line"><span>* soft nofile 1024</span></span>
<span class="line"><span>* hard nofile 2048</span></span></code></pre></div></li><li><p><strong>Disk Quotas</strong> — Enable filesystem quotas to prevent disk space exhaustion:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Set per-user quota</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setquota</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> web_user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1G</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 2G</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span></span></code></pre></div></li><li><p><strong>Network Isolation</strong> — Consider using firewall rules to restrict which ports each website user can access.</p></li><li><p><strong>Audit Logs</strong> — Terminal sessions are logged to <code>kiwipanel/logs/kiwipanel.json</code>. Monitor these logs for suspicious activity.</p></li></ol><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="sandbox-not-available-error" tabindex="-1">&quot;Sandbox not available&quot; error <a class="header-anchor" href="#sandbox-not-available-error" aria-label="Permalink to &quot;&quot;Sandbox not available&quot; error&quot;">​</a></h3><p>The systemd sandbox requires systemd v249+. Check your version:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>If your system uses an older systemd version, the terminal will fall back to the traditional shell-based restrictions only.</p><h3 id="terminal-won-t-start" tabindex="-1">Terminal won&#39;t start <a class="header-anchor" href="#terminal-won-t-start" aria-label="Permalink to &quot;Terminal won&#39;t start&quot;">​</a></h3><ol><li>Check the agent logs: <code>tail -f kiwipanel/logs/kiwipanel.json</code></li><li>Ensure the website&#39;s Linux user exists: <code>id web_user</code></li><li>Verify the terminal-bin directory exists: <code>ls /var/lib/kiwipanel/terminal-bin/</code></li></ol><hr><h3 id="commands-not-found" tabindex="-1">Commands not found <a class="header-anchor" href="#commands-not-found" aria-label="Permalink to &quot;Commands not found&quot;">​</a></h3><p>Ensure the <code>/var/lib/kiwipanel/terminal-bin/</code> directory exists and contains symlinks to allowed commands. This shared directory is created automatically on agent startup.</p>`,53)])])}const u=t(i,[["render",a]]);export{m as __pageData,u as default};
